import { FormEvent, ReactNode, useEffect, useMemo, useState } from "react";
import { Navigate, NavLink, Route, Routes, useLocation, useNavigate } from "react-router-dom";
import { Bar, BarChart, CartesianGrid, Cell, Line, LineChart as ReLineChart, Pie, PieChart, ResponsiveContainer, Tooltip, XAxis, YAxis } from "recharts";
import { ArrowUpRight, Building2, CheckCircle2, CreditCard, Edit3, Eye, EyeOff, LayoutDashboard, LineChart, LogOut, Moon, PiggyBank, Plus, Save, Search, ShieldCheck, Sun, Target, Trash2, UserCircle, WalletCards, X } from "lucide-react";
import { budgets as initialBudgets, categoryColors, defaultCategories, initialTransactions, mockSyncedTransactions } from "@/data/financeMock";
import type { BankConnection, Budget, Category, FinanceCategory, Transaction, TransactionType } from "@/types/finance";
import { budgetUsage, categoryColor, currency, filterByPeriod, monthName, previousPeriod, spendByCategory, summarize } from "@/utils/financeCalculations";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";

const navItems = [
  { label: "Dashboard", path: "/dashboard", icon: LayoutDashboard },
  { label: "Transactions", path: "/transactions", icon: CreditCard },
  { label: "Budgets", path: "/budgets", icon: Target },
  { label: "Insights", path: "/insights", icon: LineChart },
  { label: "Profile", path: "/profile", icon: UserCircle },
];
const monthOptions = Array.from({ length: 12 }, (_, index) => index + 1);
const yearOptions = [2025, 2026, 2027];
const emptyForm = { amount: "", type: "expense" as TransactionType, category: "Food" as Category, date: new Date().toISOString().slice(0, 10), description: "" };
type TransactionForm = typeof emptyForm;
type GroupBy = "none" | "date" | "category";
type UserProfile = { name: string; email: string; currency: string };

declare global {
  interface Window {
    googleTranslateElementInit?: () => void;
    google?: { translate?: { TranslateElement?: new (options: Record<string, unknown>, element: string) => void } };
  }
}

function SmartFinanceManager() {
  const [darkMode, setDarkMode] = useState(false);
  const [salary, setSalary] = useState(3200);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<UserProfile>({ name: "Alex Morgan", email: "alex@smartfinance.app", currency: "USD" });
  const [selectedMonth, setSelectedMonth] = useState(4);
  const [selectedYear, setSelectedYear] = useState(2026);
  const [transactions, setTransactions] = useState<Transaction[]>(initialTransactions);
  const [budgets, setBudgets] = useState<Budget[]>(initialBudgets);
  const [categories, setCategories] = useState<FinanceCategory[]>(defaultCategories);
  const [bankConnection, setBankConnection] = useState<BankConnection>({ connected: false, bankName: "", accountNumber: "" });
  const [bankModalOpen, setBankModalOpen] = useState(false);

  const periodTransactions = useMemo(() => filterByPeriod(transactions, selectedMonth, selectedYear), [transactions, selectedMonth, selectedYear]);
  const periodBudgets = useMemo(() => ensurePeriodBudgets(budgets, categories, selectedMonth, selectedYear, transactions), [budgets, categories, selectedMonth, selectedYear, transactions]);
  const categoryNames = categories.map((category) => category.name);
  const budgetCategoryNames = categoryNames.filter((category) => category !== "Uncategorized");

  const updateCategory = (id: string, category: Category) => setTransactions((current) => current.map((transaction) => transaction.id === id ? { ...transaction, category } : transaction));
  const addTransaction = (form: TransactionForm) => setTransactions((current) => [{ id: crypto.randomUUID(), amount: Number(form.amount), date: form.date, merchant: form.description, description: form.description, type: form.type, status: "manual", category: form.category, source: "manual" }, ...current]);
  const editTransaction = (id: string, form: TransactionForm) => setTransactions((current) => current.map((transaction) => transaction.id === id ? { ...transaction, amount: Number(form.amount), date: form.date, merchant: form.description, description: form.description, type: form.type, category: form.category } : transaction));
  const deleteTransaction = (id: string) => setTransactions((current) => current.filter((transaction) => transaction.id !== id));
  const deleteTransactions = (ids: string[]) => setTransactions((current) => current.filter((transaction) => !ids.includes(transaction.id)));
  const updateBudget = (category: Category, monthlyLimit: number) => setBudgets((current) => upsertBudget(current, category, monthlyLimit, selectedMonth, selectedYear));
  const syncBank = () => setTransactions((current) => [...mockSyncedTransactions.map((transaction) => ({ ...transaction, id: crypto.randomUUID(), date: `${selectedYear}-${String(selectedMonth).padStart(2, "0")}-${String(10 + Math.ceil(Math.random() * 15)).padStart(2, "0")}`, category: "Uncategorized" })), ...current]);
  const saveCategory = (category: FinanceCategory) => setCategories((current) => current.some((item) => item.id === category.id) ? current.map((item) => item.id === category.id ? category : item) : [...current, category]);
  const deleteCategory = (name: string) => { if (name === "Uncategorized") return; setCategories((current) => current.filter((category) => category.name !== name)); setTransactions((current) => current.map((transaction) => transaction.category === name ? { ...transaction, category: "Uncategorized" } : transaction)); setBudgets((current) => current.filter((budget) => budget.category !== name)); };

  const login = (email: string, name = email.split("@")[0] || "Finance User") => { setUser((current) => ({ ...current, name, email })); setIsLoggedIn(true); };
  const logout = () => setIsLoggedIn(false);

  return (
    <div className={darkMode ? "dark" : ""}>
      <main className="min-h-screen bg-background text-foreground">
        <Routes>
          <Route path="/" element={<PublicOnly isLoggedIn={isLoggedIn}><LandingPage /></PublicOnly>} />
          <Route path="/login" element={<PublicOnly isLoggedIn={isLoggedIn}><LoginPage onLogin={login} /></PublicOnly>} />
          <Route path="/signup" element={<PublicOnly isLoggedIn={isLoggedIn}><SignupPage onSignup={login} /></PublicOnly>} />
          <Route path="/*" element={<ProtectedShell isLoggedIn={isLoggedIn} user={user} salary={salary} darkMode={darkMode} selectedMonth={selectedMonth} selectedYear={selectedYear} bankConnection={bankConnection} onMonth={setSelectedMonth} onYear={setSelectedYear} onSalary={setSalary} onBank={() => setBankModalOpen(true)} onSync={syncBank} onDark={() => setDarkMode(!darkMode)} /> } />
        </Routes>
        <LanguageSwitcher />
      </main>
      {isLoggedIn && bankModalOpen && <BankModal connection={bankConnection} onClose={() => setBankModalOpen(false)} onConnect={(connection) => { setBankConnection(connection); setBankModalOpen(false); }} />}
    </div>
  );

  function ProtectedShell({ isLoggedIn, user, salary, darkMode, selectedMonth, selectedYear, bankConnection, onMonth, onYear, onSalary, onBank, onSync, onDark }: { isLoggedIn: boolean; user: UserProfile; salary: number; darkMode: boolean; selectedMonth: number; selectedYear: number; bankConnection: BankConnection; onMonth: (value: number) => void; onYear: (value: number) => void; onSalary: (value: number) => void; onBank: () => void; onSync: () => void; onDark: () => void }) {
    const navigate = useNavigate();
    if (!isLoggedIn) return <Navigate to="/login" replace />;
    return <section className="flex min-h-screen flex-col bg-hero lg:flex-row">
          <AppSidebar />
          <div className="flex-1 overflow-hidden">
            <header className="sticky top-0 z-20 border-b bg-card/75 px-4 py-4 shadow-soft backdrop-blur-xl md:px-6 lg:px-8">
              <div className="flex flex-col gap-4 xl:flex-row xl:items-end xl:justify-between">
                <div><p className="text-sm font-semibold text-primary">Personal finance workspace</p><h1 className="font-display text-3xl font-bold md:text-4xl">Smart Finance Manager</h1></div>
                <div className="flex flex-wrap items-end gap-3">
                  <label className="block min-w-44 text-sm font-semibold">Month<select value={selectedMonth} onChange={(event) => onMonth(Number(event.target.value))} className="mt-1 h-10 w-full rounded-lg border bg-card/80 px-3 outline-none transition focus:ring-2 focus:ring-ring">{monthOptions.map((month) => <option key={month} value={month}>{monthName(month)}</option>)}</select></label>
                  <label className="block min-w-32 text-sm font-semibold">Year<select value={selectedYear} onChange={(event) => onYear(Number(event.target.value))} className="mt-1 h-10 w-full rounded-lg border bg-card/80 px-3 outline-none transition focus:ring-2 focus:ring-ring">{yearOptions.map((year) => <option key={year}>{year}</option>)}</select></label>
                  <label className="block min-w-44 text-sm font-semibold">Monthly Salary<input value={salary || ""} onChange={(event) => onSalary(Number(event.target.value))} type="number" min="0" className="mt-1 h-10 w-full rounded-lg border bg-card/80 px-3 outline-none transition focus:ring-2 focus:ring-ring" /></label>
                  <button onClick={onBank} className="premium-button inline-flex h-10 items-center gap-2 rounded-lg border bg-card/80 px-3 font-semibold transition hover:border-primary" title="Connect a mock bank account"><Building2 className="h-4 w-4" />{bankConnection.connected ? "Bank Connected" : "Connect Bank"}</button>
                  <button onClick={onSync} disabled={!bankConnection.connected} className="premium-button inline-flex h-10 items-center gap-2 rounded-lg bg-primary-gradient px-3 font-semibold text-primary-foreground disabled:cursor-not-allowed disabled:opacity-50" title="Generate mock synced transactions"><CreditCard className="h-4 w-4" />Sync Transactions</button>
                  <button onClick={onDark} className="premium-button inline-flex h-10 items-center gap-2 rounded-lg border bg-card/80 px-3 font-semibold transition hover:border-primary" aria-label="Toggle dark mode">{darkMode ? <Sun className="h-4 w-4" /> : <Moon className="h-4 w-4" />}<span className="hidden sm:inline">Mode</span></button>
                  <button onClick={() => navigate("/profile")} className="premium-button inline-flex h-10 items-center gap-2 rounded-lg border bg-card/80 px-3 font-semibold transition hover:border-primary"><UserCircle className="h-4 w-4" />{user.name}</button>
                </div>
              </div>
            </header>
            <div className="p-4 md:p-6 lg:p-8">
              <Routes>
                <Route path="/" element={<Navigate to="/dashboard" replace />} />
                <Route path="/dashboard" element={<DashboardPage salary={salary} transactions={periodTransactions} allTransactions={transactions} budgets={periodBudgets} categories={categories} month={selectedMonth} year={selectedYear} onQuickAdd={addTransaction} onBudget={updateBudget} />} />
                <Route path="/transactions" element={<TransactionsPage transactions={periodTransactions} categories={categories} categoryNames={categoryNames} onAdd={addTransaction} onEdit={editTransaction} onDelete={deleteTransaction} onBulkDelete={deleteTransactions} onCategoryChange={updateCategory} onSaveCategory={saveCategory} onDeleteCategory={deleteCategory} />} />
                <Route path="/budgets" element={<BudgetsPage salary={salary} transactions={periodTransactions} allTransactions={transactions} budgets={periodBudgets} categories={categories} categoryNames={budgetCategoryNames} month={selectedMonth} year={selectedYear} onUpdateBudget={updateBudget} />} />
                <Route path="/insights" element={<InsightsPage salary={salary} transactions={periodTransactions} allTransactions={transactions} categories={categories} month={selectedMonth} year={selectedYear} />} />
                <Route path="/profile" element={<ProfilePage user={user} salary={salary} darkMode={darkMode} onUser={setUser} onSalary={setSalary} onDark={setDarkMode} onLogout={logout} />} />
                <Route path="*" element={<Navigate to="/dashboard" replace />} />
              </Routes>
            </div>
          </div>
        </section>;
  }
}

function LanguageSwitcher() {
  useEffect(() => {
    if (!document.getElementById("google-translate-script")) {
      window.googleTranslateElementInit = () => {
        if (window.google?.translate?.TranslateElement) {
          new window.google.translate.TranslateElement({ pageLanguage: "en", includedLanguages: "en,hi,te,ta,kn,ml,bn,gu,mr,pa,ur,ar,fr,es,de,zh-CN,ja,ko", autoDisplay: false }, "google_translate_element");
        }
      };
      const script = document.createElement("script");
      script.id = "google-translate-script";
      script.src = "https://translate.google.com/translate_a/element.js?cb=googleTranslateElementInit";
      document.body.appendChild(script);
    }
  }, []);

  return <div className="fixed bottom-4 right-4 z-50 rounded-lg border bg-card/95 p-3 text-sm font-semibold shadow-soft backdrop-blur"><span className="mb-2 block text-xs text-muted-foreground">Language</span><div id="google_translate_element" /></div>;
}

function AppSidebar() { return <aside className="border-b bg-sidebar/95 text-sidebar-foreground shadow-soft backdrop-blur-xl transition-all lg:min-h-screen lg:w-64 lg:border-b-0 lg:border-r lg:border-sidebar-border"><div className="flex items-center gap-2 p-4 font-bold"><span className="grid h-9 w-9 place-items-center rounded-md bg-sidebar-primary text-sidebar-primary-foreground"><PiggyBank className="h-5 w-5" /></span>Smart Finance</div><nav className="flex gap-2 overflow-x-auto px-4 pb-4 lg:mt-8 lg:block lg:space-y-2 lg:pb-0">{navItems.map((item) => <NavLink key={item.path} to={item.path} className={({ isActive }) => isActive ? "flex shrink-0 items-center gap-3 rounded-lg bg-sidebar-primary px-3 py-2 font-semibold text-sidebar-primary-foreground shadow-glow lg:w-full" : "flex shrink-0 items-center gap-3 rounded-lg px-3 py-2 text-sidebar-foreground/75 transition hover:translate-x-1 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground lg:w-full"}><item.icon className="h-4 w-4" />{item.label}</NavLink>)}</nav></aside>; }

function PublicOnly({ isLoggedIn, children }: { isLoggedIn: boolean; children: ReactNode }) { return isLoggedIn ? <Navigate to="/dashboard" replace /> : <>{children}</>; }
function LandingPage() {
  const features = [
    { title: "Expense Tracking", description: "Capture every income and expense with clear categories and instant context.", icon: CreditCard },
    { title: "Budget Management", description: "Plan monthly limits, monitor usage, and stay ahead before overspending.", icon: Target },
    { title: "Smart Insights", description: "Understand trends, savings gaps, and spending changes at a glance.", icon: LineChart },
    { title: "Bank Sync", description: "Preview connected-account workflows with smooth mock transaction imports.", icon: Building2 },
  ];
  const stats = ["10,000+ active users", "1M+ transactions tracked", "94% clearer budgets", "24/7 money visibility"];
  const steps = [
    { title: "Create your account", text: "Set up your workspace in seconds.", icon: UserCircle },
    { title: "Add or sync transactions", text: "Bring spending data into one place.", icon: CreditCard },
    { title: "Track and analyze spending", text: "Turn numbers into practical decisions.", icon: LineChart },
  ];

  return <div className="min-h-screen overflow-hidden bg-background">
    <header className="sticky top-0 z-30 border-b bg-card/75 px-4 py-4 shadow-soft backdrop-blur-xl">
      <div className="mx-auto flex max-w-7xl items-center justify-between gap-4">
        <NavLink to="/" className="flex items-center gap-2 text-base font-extrabold tracking-tight transition hover:text-primary"><span className="grid h-10 w-10 place-items-center rounded-lg bg-primary-gradient text-primary-foreground shadow-glow"><PiggyBank className="h-5 w-5" /></span>Smart Finance</NavLink>
        <nav className="flex items-center gap-2"><NavLink to="/login" className="premium-button rounded-lg border bg-card/70 px-4 py-2 text-sm font-bold hover:border-primary">Login</NavLink><NavLink to="/signup" className="premium-button rounded-lg bg-primary-gradient px-4 py-2 text-sm font-extrabold text-primary-foreground shadow-soft">Signup</NavLink></nav>
      </div>
    </header>

    <section className="relative border-b bg-hero finance-grid px-4 py-16 md:py-24">
      <div className="mx-auto grid max-w-7xl items-center gap-12 lg:grid-cols-[1fr_.95fr]">
        <div className="animate-slide-up">
          <p className="mb-5 inline-flex items-center gap-2 rounded-full border bg-card/80 px-4 py-2 text-sm font-bold text-primary shadow-soft backdrop-blur"><ShieldCheck className="h-4 w-4" />Premium frontend finance workspace</p>
          <h1 className="max-w-3xl font-display text-5xl font-black leading-tight tracking-tight text-foreground md:text-7xl">Smart Finance Manager</h1>
          <p className="mt-6 max-w-2xl text-xl font-medium leading-8 text-muted-foreground md:text-2xl">Track, analyze, and control your finances effortlessly</p>
          <div className="mt-9 flex flex-wrap gap-3"><NavLink to="/signup" className="premium-button inline-flex items-center gap-2 rounded-lg bg-accent px-6 py-3 font-extrabold text-accent-foreground shadow-glow">Get Started<ArrowUpRight className="h-4 w-4" /></NavLink><NavLink to="/login" className="premium-button rounded-lg border bg-card/80 px-6 py-3 font-extrabold text-foreground shadow-soft backdrop-blur hover:border-primary">Login</NavLink></div>
        </div>

        <div className="hero-visual-in relative min-h-[30rem]" aria-label="Finance dashboard preview illustration">
          <div className="absolute inset-x-0 top-4 rounded-xl border bg-card/80 p-5 shadow-glow backdrop-blur-xl">
            <div className="mb-5 flex items-center justify-between"><div><p className="text-sm font-bold text-muted-foreground">Monthly balance</p><p className="text-4xl font-black text-foreground">$8,420</p></div><span className="rounded-full bg-accent px-4 py-2 text-sm font-black text-accent-foreground">+18%</span></div>
            <div className="grid h-32 grid-cols-7 items-end gap-3">{[42, 66, 48, 76, 58, 92, 70].map((height, index) => <span key={index} className="chart-grow rounded-t-lg bg-primary-gradient shadow-soft" style={{ height: `${height}%`, animationDelay: `${index * 80}ms` }} />)}</div>
          </div>
          <div className="float-a absolute bottom-20 left-0 w-60 rounded-xl border bg-card/85 p-5 shadow-soft backdrop-blur-xl"><p className="text-sm font-bold text-muted-foreground">Top category</p><p className="mt-2 text-2xl font-black">Bills</p><div className="mt-4 h-3 rounded-full bg-muted"><div className="h-full w-4/5 rounded-full bg-accent" /></div></div>
          <div className="float-b absolute bottom-6 right-0 w-64 rounded-xl border bg-card/85 p-5 shadow-soft backdrop-blur-xl"><p className="text-sm font-bold text-muted-foreground">Bank sync</p><div className="mt-4 space-y-2">{["Payroll", "Groceries", "Transport"].map((item) => <div key={item} className="flex items-center justify-between rounded-lg bg-muted/45 px-3 py-2 font-semibold"><span>{item}</span><CheckCircle2 className="h-4 w-4 text-primary" /></div>)}</div></div>
          <div className="float-c absolute right-8 top-56 rounded-xl border bg-card/90 px-4 py-3 shadow-soft backdrop-blur-xl"><p className="text-xs font-bold uppercase text-muted-foreground">Saved this month</p><p className="text-xl font-black text-success">$1,280</p></div>
        </div>
      </div>
    </section>

    <section className="mx-auto grid max-w-7xl gap-4 px-4 py-14 sm:grid-cols-2 lg:grid-cols-4">{stats.map((stat) => <div key={stat} className="premium-card p-5 text-center"><p className="text-2xl font-black text-foreground">{stat.split(" ")[0]}</p><p className="mt-1 text-sm font-semibold text-muted-foreground">{stat.replace(stat.split(" ")[0], "").trim()}</p></div>)}</section>

    <section className="mx-auto max-w-7xl px-4 py-10"><div className="mb-8 max-w-2xl"><h2 className="font-display text-3xl font-black md:text-4xl">Everything your money needs</h2><p className="mt-3 text-muted-foreground">Clean tools, thoughtful interactions, and readable financial views built for daily use.</p></div><div className="grid gap-5 md:grid-cols-2 lg:grid-cols-4">{features.map((feature) => <div key={feature.title} className="premium-card p-6"><span className="mb-5 grid h-12 w-12 place-items-center rounded-xl bg-primary/10 text-primary"><feature.icon className="h-6 w-6" /></span><h3 className="text-lg font-black">{feature.title}</h3><p className="mt-3 text-sm leading-6 text-muted-foreground">{feature.description}</p></div>)}</div></section>

    <section className="border-y bg-muted/25 px-4 py-16"><div className="mx-auto max-w-7xl"><h2 className="font-display text-3xl font-black md:text-4xl">How It Works</h2><div className="mt-8 grid gap-5 md:grid-cols-3">{steps.map((step, index) => <div key={step.title} className="premium-card p-6"><div className="mb-5 flex items-center justify-between"><span className="grid h-14 w-14 place-items-center rounded-xl bg-primary-gradient text-primary-foreground shadow-soft"><step.icon className="h-7 w-7" /></span><span className="text-sm font-black text-primary">Step {index + 1}</span></div><h3 className="text-xl font-black">{step.title}</h3><p className="mt-3 text-sm leading-6 text-muted-foreground">{step.text}</p></div>)}</div></div></section>

    <section className="px-4 py-16"><div className="mx-auto max-w-5xl rounded-xl bg-primary-gradient px-6 py-14 text-center text-primary-foreground shadow-glow"><h2 className="font-display text-4xl font-black">Start managing your finances today</h2><p className="mx-auto mt-4 max-w-2xl text-primary-foreground/85">Create your account and turn everyday transactions into clear, confident decisions.</p><NavLink to="/signup" className="premium-button mt-7 inline-flex items-center gap-2 rounded-lg bg-card px-6 py-3 font-black text-foreground shadow-soft">Create Account<ArrowUpRight className="h-4 w-4" /></NavLink></div></section>
  </div>;
}
function LoginPage({ onLogin }: { onLogin: (email: string) => void }) { const navigate = useNavigate(); const [email, setEmail] = useState(""); const [password, setPassword] = useState(""); const [show, setShow] = useState(false); return <AuthFrame title="Welcome back" subtitle="Login to continue managing your finances."><form onSubmit={(event) => { event.preventDefault(); if (!email || !password) return; onLogin(email); navigate("/dashboard"); }} className="space-y-4"><input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="h-11 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Email" /><label className="relative block"><input required type={show ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} className="h-11 w-full rounded-md border bg-background px-3 pr-11 outline-none focus:ring-2 focus:ring-ring" placeholder="Password" /><button type="button" onClick={() => setShow(!show)} className="absolute right-2 top-2 rounded-md p-1.5 text-muted-foreground">{show ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}</button></label><button className="premium-button w-full rounded-lg bg-primary-gradient py-3 font-bold text-primary-foreground shadow-glow">Login</button><p className="text-center text-sm text-muted-foreground">No account? <NavLink to="/signup" className="font-bold text-primary">Sign up</NavLink></p></form></AuthFrame>; }
function SignupPage({ onSignup }: { onSignup: (email: string, name: string) => void }) { const navigate = useNavigate(); const [form, setForm] = useState({ name: "", email: "", password: "", confirm: "" }); const [error, setError] = useState(""); return <AuthFrame title="Create account" subtitle="Start building better money habits today."><form onSubmit={(event) => { event.preventDefault(); if (!form.name || !form.email || !form.password || !form.confirm) return setError("All fields are required."); if (form.password !== form.confirm) return setError("Passwords must match."); onSignup(form.email, form.name); navigate("/dashboard"); }} className="space-y-4"><input required value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} className="h-11 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Name" /><input required type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} className="h-11 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Email" /><input required type="password" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} className="h-11 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Password" /><input required type="password" value={form.confirm} onChange={(e) => setForm({ ...form, confirm: e.target.value })} className="h-11 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Confirm Password" />{error && <p className="rounded-md bg-destructive/10 p-3 text-sm font-semibold text-destructive">{error}</p>}<button className="premium-button w-full rounded-lg bg-primary-gradient py-3 font-bold text-primary-foreground shadow-glow">Sign up</button><p className="text-center text-sm text-muted-foreground">Already have an account? <NavLink to="/login" className="font-bold text-primary">Login</NavLink></p></form></AuthFrame>; }
function AuthFrame({ title, subtitle, children }: { title: string; subtitle: string; children: ReactNode }) { return <div className="grid min-h-screen place-items-center bg-background px-4"><div className="w-full max-w-md rounded-lg border bg-card-gradient p-6 shadow-soft"><NavLink to="/" className="mb-6 flex items-center gap-2 font-bold"><PiggyBank className="h-5 w-5 text-primary" />Smart Finance</NavLink><h1 className="font-display text-3xl font-bold">{title}</h1><p className="mt-2 text-sm text-muted-foreground">{subtitle}</p><div className="mt-6">{children}</div></div></div>; }
function ProfilePage({ user, salary, darkMode, onUser, onSalary, onDark, onLogout }: { user: UserProfile; salary: number; darkMode: boolean; onUser: (user: UserProfile) => void; onSalary: (salary: number) => void; onDark: (value: boolean) => void; onLogout: () => void }) { const navigate = useNavigate(); const [draft, setDraft] = useState(user); return <div className="page-shell space-y-6"><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5 flex items-center gap-3"><UserCircle className="h-8 w-8 text-primary" /><div><h2 className="text-lg font-bold">User Info</h2><p className="text-sm text-muted-foreground">Editable mock profile details.</p></div></div><div className="grid gap-4 md:grid-cols-2"><label className="text-sm font-semibold">Name<input value={draft.name} onChange={(e) => setDraft({ ...draft, name: e.target.value })} className="mt-1 h-10 w-full rounded-md border bg-background px-3" /></label><label className="text-sm font-semibold">Email<input value={draft.email} onChange={(e) => setDraft({ ...draft, email: e.target.value })} type="email" className="mt-1 h-10 w-full rounded-md border bg-background px-3" /></label></div><button onClick={() => onUser(draft)} className="mt-4 rounded-md bg-primary px-4 py-2 font-bold text-primary-foreground">Save profile</button></section><section className="grid gap-6 lg:grid-cols-2"><div className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><h2 className="text-lg font-bold">Financial Info</h2><label className="mt-4 block text-sm font-semibold">Monthly Salary<input value={salary || ""} onChange={(e) => onSalary(Number(e.target.value))} type="number" min="0" className="mt-1 h-10 w-full rounded-md border bg-background px-3" /></label></div><div className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><h2 className="text-lg font-bold">Preferences</h2><div className="mt-4 space-y-4"><label className="flex items-center justify-between rounded-md border p-3 font-semibold">Dark mode<input type="checkbox" checked={darkMode} onChange={(e) => onDark(e.target.checked)} className="h-4 w-4" /></label><label className="block text-sm font-semibold">Currency<select value={draft.currency} onChange={(e) => { const next = { ...draft, currency: e.target.value }; setDraft(next); onUser(next); }} className="mt-1 h-10 w-full rounded-md border bg-background px-3"><option>USD</option><option>EUR</option><option>GBP</option><option>INR</option></select></label></div></div></section><button onClick={() => { onLogout(); navigate("/"); }} className="premium-button inline-flex items-center gap-2 rounded-lg bg-destructive px-4 py-2 font-bold text-destructive-foreground"><LogOut className="h-4 w-4" />Logout</button></div>; }

function DashboardPage({ salary, transactions, allTransactions, budgets, categories, month, year, onQuickAdd, onBudget }: { salary: number; transactions: Transaction[]; allTransactions: Transaction[]; budgets: Budget[]; categories: FinanceCategory[]; month: number; year: number; onQuickAdd: (form: TransactionForm) => void; onBudget: (category: Category, amount: number) => void }) {
  const navigate = useNavigate(); const [addOpen, setAddOpen] = useState(false); const [budgetOpen, setBudgetOpen] = useState(false); const totals = summarize(transactions, salary); const spending = spendByCategory(transactions); const top3 = Object.entries(spending).sort((a, b) => b[1] - a[1]).slice(0, 3); const biggest = transactions.filter((t) => t.type === "expense").sort((a, b) => b.amount - a.amount)[0]; const totalBudget = budgets.reduce((sum, budget) => sum + budget.monthlyLimit, 0); const budgetUsed = budgets.reduce((sum, budget) => sum + budgetUsage(budget, transactions).spent, 0); const weekly = weeklySpending(transactions); const prev = previousPeriod(month, year); const prevTotals = summarize(filterByPeriod(allTransactions, prev.month, prev.year), salary); const savingsTrend = totals.savings - prevTotals.savings;
  return <div className="page-shell space-y-6"><div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4"><SummaryButton label="Total Balance" value={currency(totals.balance)} helper="Salary minus expenses" icon={<WalletCards className="h-5 w-5" />} onClick={() => navigate("/insights")} /><SummaryButton label="Total Income" value={currency(totals.income)} helper="Filtered monthly income" icon={<PiggyBank className="h-5 w-5" />} onClick={() => navigate("/transactions")} /><SummaryButton label="Total Expenses" value={currency(totals.expenses)} helper={`${totals.uncategorized} uncategorized`} icon={<CreditCard className="h-5 w-5" />} onClick={() => navigate("/transactions")} /><SummaryButton label="Budget Left" value={currency(Math.max(0, totalBudget - budgetUsed))} helper="Across selected month" icon={<Target className="h-5 w-5" />} onClick={() => navigate("/budgets")} /></div><div className="grid gap-4 md:grid-cols-3"><MetricCard label="Biggest Expense" value={biggest ? currency(biggest.amount) : "$0"} helper={biggest?.description ?? "No expense yet"} /><MetricCard label="Savings Trend" value={`${savingsTrend >= 0 ? "+" : ""}${currency(savingsTrend)}`} helper="Compared with previous month" /><MetricCard label="Top Category" value={top3[0]?.[0] ?? "None"} helper={top3[0] ? currency(top3[0][1]) : "No spending"} /></div><div className="grid gap-6 xl:grid-cols-[1.1fr_.9fr]"><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5 flex items-center justify-between gap-3"><div><h2 className="text-lg font-bold">Recent transactions</h2><p className="text-sm text-muted-foreground">Latest activity in {monthName(month)} {year}.</p></div><div className="flex gap-2"><button onClick={() => setAddOpen(true)} className="premium-button rounded-lg bg-primary-gradient px-3 py-2 text-sm font-bold text-primary-foreground">Add</button><button onClick={() => navigate("/transactions")} className="premium-button rounded-lg border bg-card/70 px-3 py-2 text-sm font-semibold hover:border-primary">View all</button></div></div><div className="space-y-3">{transactions.slice(0, 5).map((transaction) => <TransactionRow key={transaction.id} transaction={transaction} categories={categories} />)}{transactions.length === 0 && <EmptyState text="No transactions for this period." />}</div></section><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5 flex items-center justify-between"><div><h2 className="text-lg font-bold">Weekly spending trend</h2><p className="text-sm text-muted-foreground">Mini chart from selected period.</p></div><button onClick={() => setBudgetOpen(true)} className="premium-button rounded-lg border bg-card/70 px-3 py-2 text-sm font-semibold hover:border-primary">Set budget</button></div><div className="h-64"><ResponsiveContainer width="100%" height="100%"><BarChart data={weekly}><XAxis dataKey="week" stroke="hsl(var(--muted-foreground))" /><YAxis stroke="hsl(var(--muted-foreground))" /><Tooltip formatter={(value: number) => currency(value)} /><Bar dataKey="spent" fill="hsl(var(--primary))" radius={[6, 6, 0, 0]} /></BarChart></ResponsiveContainer></div></section></div><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><h2 className="mb-4 text-lg font-bold">Top 3 spending categories</h2><div className="grid gap-3 md:grid-cols-3">{top3.map(([name, value]) => <MetricCard key={name} label={name} value={currency(value)} helper="Monthly spend" />)}{top3.length === 0 && <EmptyState text="No category spending yet." />}</div></section>{addOpen && <TransactionModal categories={categories.map((c) => c.name)} transaction={null} onClose={() => setAddOpen(false)} onSubmit={(form) => { onQuickAdd(form); setAddOpen(false); }} />}{budgetOpen && <BudgetQuickModal budgets={budgets} onClose={() => setBudgetOpen(false)} onSave={(category, value) => { onBudget(category, value); setBudgetOpen(false); }} />}</div>;
}

function TransactionsPage({ transactions, categories, categoryNames, onAdd, onEdit, onDelete, onBulkDelete, onCategoryChange, onSaveCategory, onDeleteCategory }: { transactions: Transaction[]; categories: FinanceCategory[]; categoryNames: Category[]; onAdd: (form: TransactionForm) => void; onEdit: (id: string, form: TransactionForm) => void; onDelete: (id: string) => void; onBulkDelete: (ids: string[]) => void; onCategoryChange: (id: string, category: Category) => void; onSaveCategory: (category: FinanceCategory) => void; onDeleteCategory: (name: string) => void }) {
  const [categoryFilter, setCategoryFilter] = useState("all"); const [typeFilter, setTypeFilter] = useState("all"); const [dateStart, setDateStart] = useState(""); const [dateEnd, setDateEnd] = useState(""); const [query, setQuery] = useState(""); const [groupBy, setGroupBy] = useState<GroupBy>("none"); const [selected, setSelected] = useState<string[]>([]); const [modalOpen, setModalOpen] = useState(false); const [editing, setEditing] = useState<Transaction | null>(null); const [categoryModal, setCategoryModal] = useState<FinanceCategory | "new" | null>(null);
  const filtered = transactions.filter((t) => (categoryFilter === "all" || t.category === categoryFilter) && (typeFilter === "all" || t.type === typeFilter) && (!dateStart || t.date >= dateStart) && (!dateEnd || t.date <= dateEnd) && (!query || `${t.description} ${t.category}`.toLowerCase().includes(query.toLowerCase()))); const totals = summarize(filtered); const groups = groupTransactions(filtered, groupBy);
  const closeModal = () => { setEditing(null); setModalOpen(false); };
  return <div className="page-shell space-y-6"><div className="grid gap-4 md:grid-cols-2"><MetricCard label="Total Income" value={currency(totals.income)} helper="Filtered transactions" /><MetricCard label="Total Expenses" value={currency(totals.expenses)} helper={`${filtered.length} visible rows`} /></div><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5 flex flex-col gap-4 xl:flex-row xl:items-end xl:justify-between"><div><h2 className="text-lg font-bold">Transactions</h2><p className="text-sm text-muted-foreground">Search, group, bulk edit, and categorize every entry.</p></div><div className="flex flex-wrap gap-3"><label className="relative"><Search className="pointer-events-none absolute left-3 top-3 h-4 w-4 text-muted-foreground" /><input value={query} onChange={(e) => setQuery(e.target.value)} className="h-10 rounded-md border bg-background pl-9 pr-3 text-sm outline-none focus:ring-2 focus:ring-ring" placeholder="Search" /></label><select value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)} className="h-10 rounded-md border bg-background px-3 text-sm"><option value="all">All categories</option>{categoryNames.map((c) => <option key={c}>{c}</option>)}</select><select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} className="h-10 rounded-md border bg-background px-3 text-sm"><option value="all">All types</option><option value="income">Income</option><option value="expense">Expense</option></select><input value={dateStart} onChange={(e) => setDateStart(e.target.value)} type="date" className="h-10 rounded-md border bg-background px-3 text-sm" title="Start date" /><input value={dateEnd} onChange={(e) => setDateEnd(e.target.value)} type="date" className="h-10 rounded-md border bg-background px-3 text-sm" title="End date" /><select value={groupBy} onChange={(e) => setGroupBy(e.target.value as GroupBy)} className="h-10 rounded-md border bg-background px-3 text-sm"><option value="none">No grouping</option><option value="date">Group by date</option><option value="category">Group by category</option></select><button onClick={() => { setQuery(""); setCategoryFilter("all"); setTypeFilter("all"); setDateStart(""); setDateEnd(""); }} className="premium-button rounded-lg border bg-card/70 px-3 py-2 text-sm font-semibold hover:border-primary">Clear</button><button onClick={() => setCategoryModal("new")} className="premium-button rounded-lg border bg-card/70 px-3 py-2 text-sm font-semibold hover:border-primary">Categories</button><button onClick={() => setModalOpen(true)} className="inline-flex items-center gap-2 rounded-md bg-primary-gradient px-4 py-2 font-bold text-primary-foreground shadow-glow"><Plus className="h-4 w-4" />Add Transaction</button></div></div>{selected.length > 0 && <div className="mb-4 flex items-center justify-between rounded-md border border-warning/40 bg-warning/10 p-3"><span className="font-semibold">{selected.length} selected</span><button onClick={() => { onBulkDelete(selected); setSelected([]); }} className="rounded-md bg-destructive px-3 py-2 text-sm font-bold text-destructive-foreground">Delete selected</button></div>}<div className="space-y-6">{Object.entries(groups).map(([group, rows]) => <div key={group}><h3 className="mb-2 font-bold text-muted-foreground">{group}</h3><TransactionTable rows={rows} categories={categories} selected={selected} setSelected={setSelected} onCategoryChange={onCategoryChange} onEdit={(transaction) => { setEditing(transaction); setModalOpen(true); }} onDelete={onDelete} /></div>)}{filtered.length === 0 && <EmptyState text="No transactions match your filters." />}</div></section><CategoryManager categories={categories} active={categoryModal} onEdit={setCategoryModal} onClose={() => setCategoryModal(null)} onSave={onSaveCategory} onDelete={onDeleteCategory} />{modalOpen && <TransactionModal categories={categoryNames.filter((c) => c !== "Uncategorized")} transaction={editing} onClose={closeModal} onSubmit={(form) => { editing ? onEdit(editing.id, form) : onAdd(form); closeModal(); }} />}</div>;
}

function BudgetsPage({ salary, transactions, allTransactions, budgets, categories, categoryNames, month, year, onUpdateBudget }: { salary: number; transactions: Transaction[]; allTransactions: Transaction[]; budgets: Budget[]; categories: FinanceCategory[]; categoryNames: Category[]; month: number; year: number; onUpdateBudget: (category: Category, monthlyLimit: number) => void }) {
  const [drafts, setDrafts] = useState<Record<string, string>>({}); const [drill, setDrill] = useState<Category | null>(null); const prev = previousPeriod(month, year); const prevSpending = spendByCategory(filterByPeriod(allTransactions, prev.month, prev.year)); const totalUsed = budgets.reduce((sum, budget) => sum + budgetUsage(budget, transactions).spent, 0); const drillRows = drill ? transactions.filter((t) => t.category === drill) : [];
  return <div className="page-shell space-y-6"><div className="grid gap-4 md:grid-cols-2"><MetricCard label="Total Budget Used" value={currency(totalUsed)} helper="Selected month" /><MetricCard label="Remaining from Salary" value={currency(salary - totalUsed)} helper="Salary minus budget spend" /></div><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5"><h2 className="text-lg font-bold">Month-wise budgets</h2><p className="text-sm text-muted-foreground">Budgets reset for {monthName(month)} {year}; suggestions use previous month spending.</p></div><div className="space-y-4">{budgets.filter((b) => categoryNames.includes(b.category)).map((budget) => { const usage = budgetUsage(budget, transactions); const suggested = prevSpending[budget.category] ?? salary * 0.12; return <div key={budget.category} onClick={() => setDrill(budget.category)} className="cursor-pointer rounded-md border bg-background/70 p-4 transition hover:border-primary"><div className="grid gap-3 lg:grid-cols-[1fr_9rem_9rem_9rem_9rem_9rem] lg:items-center"><div><p className="font-bold" style={{ color: categoryColor(categories, budget.category) }}>{budget.category}</p><p className="text-sm text-muted-foreground">Suggested: {currency(suggested)}</p></div><MetricInline label="Limit" value={currency(budget.monthlyLimit)} /><MetricInline label="Spent" value={currency(usage.spent)} /><MetricInline label="Remaining" value={currency(usage.remaining)} /><MetricInline label="Used" value={`${usage.rawPercent}%`} /><div className="flex gap-2" onClick={(e) => e.stopPropagation()}><input value={drafts[budget.category] ?? String(budget.monthlyLimit)} onChange={(event) => setDrafts({ ...drafts, [budget.category]: event.target.value })} type="number" min="0" className="h-10 min-w-0 rounded-md border bg-card px-2 text-sm outline-none focus:ring-2 focus:ring-ring" /><button onClick={() => onUpdateBudget(budget.category, Number(drafts[budget.category] ?? budget.monthlyLimit))} className="rounded-md bg-primary px-3 text-primary-foreground"><Save className="h-4 w-4" /></button></div></div><div className="mt-4 h-3 overflow-hidden rounded-full bg-muted"><div className={usage.rawPercent > 100 ? "h-full rounded-full bg-destructive transition-all" : usage.rawPercent >= 80 ? "h-full rounded-full bg-warning transition-all" : "h-full rounded-full bg-primary-gradient transition-all"} style={{ width: `${Math.min(100, usage.rawPercent)}%` }} /></div>{usage.rawPercent > 100 ? <p className="mt-2 text-sm font-bold text-destructive">Over budget</p> : usage.rawPercent >= 80 ? <p className="mt-2 text-sm font-bold text-warning">Warning: over 80% used</p> : null}</div>; })}</div></section><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><h2 className="mb-4 text-lg font-bold">Category Breakdown Table</h2><Table><TableHeader><TableRow><TableHead>Category</TableHead><TableHead>Budget Limit</TableHead><TableHead>Total Spent</TableHead><TableHead>Remaining</TableHead><TableHead>% Used</TableHead></TableRow></TableHeader><TableBody>{budgets.filter((b) => categoryNames.includes(b.category)).map((budget) => { const usage = budgetUsage(budget, transactions); return <TableRow key={budget.category}><TableCell className="font-bold">{budget.category}</TableCell><TableCell>{currency(budget.monthlyLimit)}</TableCell><TableCell>{currency(usage.spent)}</TableCell><TableCell>{currency(usage.remaining)}</TableCell><TableCell>{usage.rawPercent}%</TableCell></TableRow>; })}</TableBody></Table></section>{drill && <ModalFrame title={`${drill} transactions`} onClose={() => setDrill(null)}><div className="space-y-3">{drillRows.map((transaction) => <TransactionRow key={transaction.id} transaction={transaction} categories={categories} />)}{drillRows.length === 0 && <EmptyState text="No transactions in this category." />}</div></ModalFrame>}</div>;
}

function InsightsPage({ salary, transactions, allTransactions, categories, month, year }: { salary: number; transactions: Transaction[]; allTransactions: Transaction[]; categories: FinanceCategory[]; month: number; year: number }) {
  const totals = summarize(transactions, salary); const spending = spendByCategory(transactions); const categoryData = Object.entries(spending).filter(([name, value]) => name !== "Uncategorized" && value > 0).map(([name, value]) => ({ name, value })); const prev = previousPeriod(month, year); const prevTransactions = filterByPeriod(allTransactions, prev.month, prev.year); const prevTotals = summarize(prevTransactions, salary); const prevSpend = spendByCategory(prevTransactions); const trend = monthlyTrend(allTransactions, salary); const monthlyDelta = totals.expenses - prevTotals.expenses; const growth = Object.keys({ ...spending, ...prevSpend }).map((name) => ({ name, delta: (spending[name] ?? 0) - (prevSpend[name] ?? 0) })).sort((a, b) => Math.abs(b.delta) - Math.abs(a.delta)); const overspent = growth.filter((item) => item.delta > 0).slice(0, 3); const saved = growth.filter((item) => item.delta < 0).slice(0, 3);
  return <div className="page-shell space-y-6"><div className="grid gap-4 md:grid-cols-4"><MetricCard label="Monthly Comparison" value={`${monthlyDelta >= 0 ? "+" : ""}${currency(monthlyDelta)}`} helper="Expenses vs last month" /><MetricCard label="Expenses vs Income" value={`${Math.round((totals.expenses / Math.max(totals.income, 1)) * 100)}%`} helper="Current period" /><MetricCard label="Savings Amount" value={currency(totals.savings)} helper="Income minus expenses" /><MetricCard label="Highest Spending" value={categoryData.sort((a, b) => b.value - a.value)[0]?.name ?? "None"} helper="Top category" /></div><div className="grid gap-6 xl:grid-cols-2"><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5"><h2 className="text-lg font-bold">Spending by Category</h2><p className="text-sm text-muted-foreground">Pie chart based on filtered expenses.</p></div><div className="h-80">{categoryData.length ? <ResponsiveContainer width="100%" height="100%"><PieChart><Pie data={categoryData} dataKey="value" nameKey="name" outerRadius={112} label>{categoryData.map((item) => <Cell key={item.name} fill={categoryColor(categories, item.name)} />)}</Pie><Tooltip formatter={(value: number) => currency(value)} /></PieChart></ResponsiveContainer> : <EmptyState text="No expense data to chart." />}</div></section><section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><div className="mb-5"><h2 className="text-lg font-bold">Income vs Expense Trend</h2><p className="text-sm text-muted-foreground">Line chart across available months.</p></div><div className="h-80"><ResponsiveContainer width="100%" height="100%"><ReLineChart data={trend}><CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" /><XAxis dataKey="month" stroke="hsl(var(--muted-foreground))" /><YAxis stroke="hsl(var(--muted-foreground))" /><Tooltip formatter={(value: number) => currency(value)} /><Line type="monotone" dataKey="income" stroke="hsl(var(--success))" strokeWidth={3} /><Line type="monotone" dataKey="expenses" stroke="hsl(var(--warning))" strokeWidth={3} /></ReLineChart></ResponsiveContainer></div></section></div><section className="grid gap-6 xl:grid-cols-3"><InsightList title="Category growth / decline" items={growth.slice(0, 5).map((item) => `${item.name}: ${item.delta >= 0 ? "+" : ""}${currency(item.delta)}`)} /><InsightList title="Where you overspent" items={overspent.map((item) => `${item.name}: +${currency(item.delta)}`)} /><InsightList title="Where you saved money" items={saved.map((item) => `${item.name}: ${currency(Math.abs(item.delta))} less`)} /></section></div>;
}

function TransactionTable({ rows, categories, selected, setSelected, onCategoryChange, onEdit, onDelete }: { rows: Transaction[]; categories: FinanceCategory[]; selected: string[]; setSelected: (ids: string[]) => void; onCategoryChange: (id: string, category: Category) => void; onEdit: (transaction: Transaction) => void; onDelete: (id: string) => void }) { const allSelected = rows.length > 0 && rows.every((row) => selected.includes(row.id)); return <Table className="table-premium"><TableHeader><TableRow><TableHead><input type="checkbox" checked={allSelected} onChange={(e) => setSelected(e.target.checked ? Array.from(new Set([...selected, ...rows.map((r) => r.id)])) : selected.filter((id) => !rows.some((r) => r.id === id)))} /></TableHead><TableHead>Date</TableHead><TableHead>Amount</TableHead><TableHead>Type</TableHead><TableHead>Category</TableHead><TableHead>Description</TableHead><TableHead>Source</TableHead><TableHead className="text-right">Actions</TableHead></TableRow></TableHeader><TableBody>{rows.map((transaction) => <TableRow key={transaction.id} className={transaction.category === "Uncategorized" ? "bg-warning/10" : undefined}><TableCell><input type="checkbox" checked={selected.includes(transaction.id)} onChange={(e) => setSelected(e.target.checked ? [...selected, transaction.id] : selected.filter((id) => id !== transaction.id))} /></TableCell><TableCell className="font-medium">{transaction.date}</TableCell><TableCell className={transaction.type === "income" ? "font-bold text-success" : "font-bold"}>{transaction.type === "income" ? "+" : "-"}{currency(transaction.amount)}</TableCell><TableCell className="capitalize">{transaction.type}</TableCell><TableCell><select value={transaction.category} onChange={(event) => onCategoryChange(transaction.id, event.target.value)} className="h-9 rounded-md border bg-background px-2 text-sm outline-none focus:ring-2 focus:ring-ring">{categories.map((category) => <option key={category.id}>{category.name}</option>)}</select></TableCell><TableCell>{transaction.description}</TableCell><TableCell><span className={transaction.source === "bank" ? "rounded-full bg-secondary/15 px-2 py-1 text-xs font-bold text-secondary" : "rounded-full bg-muted px-2 py-1 text-xs font-bold text-muted-foreground"}>{transaction.source === "bank" ? "Bank Sync" : "Manual"}</span></TableCell><TableCell className="text-right"><div className="flex justify-end gap-2"><button onClick={() => onEdit(transaction)} className="rounded-md border p-2 hover:border-primary" aria-label="Edit transaction"><Edit3 className="h-4 w-4" /></button><button onClick={() => onDelete(transaction.id)} className="rounded-md border p-2 text-destructive hover:border-destructive" aria-label="Delete transaction"><Trash2 className="h-4 w-4" /></button></div></TableCell></TableRow>)}</TableBody></Table>; }
function TransactionModal({ transaction, categories, onClose, onSubmit }: { transaction: Transaction | null; categories: Category[]; onClose: () => void; onSubmit: (form: TransactionForm) => void }) { const [form, setForm] = useState<TransactionForm>(transaction ? { amount: String(transaction.amount), type: transaction.type, category: transaction.category === "Uncategorized" ? categories[0] : transaction.category, date: transaction.date, description: transaction.description } : { ...emptyForm, category: categories[0] ?? "Others" }); const submit = (event: FormEvent<HTMLFormElement>) => { event.preventDefault(); if (!form.amount || !form.description.trim()) return; onSubmit(form); }; return <ModalFrame title={transaction ? "Edit transaction" : "Add transaction"} onClose={onClose}><form onSubmit={submit} className="space-y-3"><input required value={form.amount} onChange={(e) => setForm({ ...form, amount: e.target.value })} type="number" min="0" step="0.01" className="h-10 w-full rounded-md border bg-background px-3 outline-none focus:ring-2 focus:ring-ring" placeholder="Amount" /><select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value as TransactionType })} className="h-10 w-full rounded-md border bg-background px-3"><option value="income">Income</option><option value="expense">Expense</option></select><select value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })} className="h-10 w-full rounded-md border bg-background px-3">{categories.map((category) => <option key={category}>{category}</option>)}</select><input required value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} type="date" className="h-10 w-full rounded-md border bg-background px-3" /><textarea required value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} className="min-h-24 w-full rounded-md border bg-background px-3 py-2" placeholder="Description" /><button className="inline-flex w-full items-center justify-center gap-2 rounded-md bg-primary-gradient py-2.5 font-bold text-primary-foreground"><Save className="h-4 w-4" />Save transaction</button></form></ModalFrame>; }
function CategoryManager({ categories, active, onEdit, onClose, onSave, onDelete }: { categories: FinanceCategory[]; active: FinanceCategory | "new" | null; onEdit: (value: FinanceCategory | "new" | null) => void; onClose: () => void; onSave: (category: FinanceCategory) => void; onDelete: (name: string) => void }) { if (!active) return null; const editing = active === "new" ? null : active; return <ModalFrame title="Category management" onClose={onClose}><div className="mb-4 grid gap-2">{categories.map((category) => <div key={category.id} className="flex items-center justify-between rounded-md border p-2"><span className="flex items-center gap-2 font-semibold"><span className="h-3 w-3 rounded-full" style={{ backgroundColor: category.color }} />{category.name}</span><div className="flex gap-2"><button onClick={() => onEdit(category)} className="rounded-md border px-2 py-1 text-sm">Edit</button><button onClick={() => onDelete(category.name)} disabled={category.isDefault} className="rounded-md border px-2 py-1 text-sm text-destructive disabled:opacity-40">Delete</button></div></div>)}</div><CategoryForm category={editing} onSave={(category) => { onSave(category); onEdit("new"); }} /></ModalFrame>; }
function CategoryForm({ category, onSave }: { category: FinanceCategory | null; onSave: (category: FinanceCategory) => void }) { const [name, setName] = useState(category?.name ?? ""); const [color, setColor] = useState(category?.color ?? categoryColors[0]); return <form onSubmit={(e) => { e.preventDefault(); if (name.trim()) onSave({ id: category?.id ?? crypto.randomUUID(), name: name.trim(), color, isDefault: category?.isDefault }); }} className="grid gap-3"><input value={name} onChange={(e) => setName(e.target.value)} className="h-10 rounded-md border bg-background px-3" placeholder="Category name" /><select value={color} onChange={(e) => setColor(e.target.value)} className="h-10 rounded-md border bg-background px-3">{categoryColors.map((item) => <option key={item} value={item}>{item.replace("hsl(var(--", "").replace("))", "")}</option>)}</select><button className="rounded-md bg-primary py-2 font-bold text-primary-foreground">Save category</button></form>; }
function BankModal({ connection, onClose, onConnect }: { connection: BankConnection; onClose: () => void; onConnect: (connection: BankConnection) => void }) { const [bankName, setBankName] = useState(connection.bankName); const [accountNumber, setAccountNumber] = useState(connection.accountNumber); return <ModalFrame title="Connect Bank Account" onClose={onClose}><form onSubmit={(e) => { e.preventDefault(); onConnect({ connected: true, bankName, accountNumber }); }} className="space-y-3"><input required value={bankName} onChange={(e) => setBankName(e.target.value)} className="h-10 w-full rounded-md border bg-background px-3" placeholder="Bank name" /><input required value={accountNumber} onChange={(e) => setAccountNumber(e.target.value)} className="h-10 w-full rounded-md border bg-background px-3" placeholder="Mock account number" /><button className="w-full rounded-md bg-primary-gradient py-2.5 font-bold text-primary-foreground">Confirm connection</button></form></ModalFrame>; }
function BudgetQuickModal({ budgets, onClose, onSave }: { budgets: Budget[]; onClose: () => void; onSave: (category: Category, value: number) => void }) { const [category, setCategory] = useState(budgets[0]?.category ?? "Food"); const [value, setValue] = useState(String(budgets[0]?.monthlyLimit ?? 0)); return <ModalFrame title="Set budget" onClose={onClose}><form onSubmit={(e) => { e.preventDefault(); onSave(category, Number(value)); }} className="space-y-3"><select value={category} onChange={(e) => setCategory(e.target.value)} className="h-10 w-full rounded-md border bg-background px-3">{budgets.map((b) => <option key={b.category}>{b.category}</option>)}</select><input value={value} onChange={(e) => setValue(e.target.value)} type="number" className="h-10 w-full rounded-md border bg-background px-3" /><button className="w-full rounded-md bg-primary py-2 font-bold text-primary-foreground">Save budget</button></form></ModalFrame>; }
function ModalFrame({ title, children, onClose }: { title: string; children: ReactNode; onClose: () => void }) { return <div className="fixed inset-0 z-50 grid place-items-center bg-background/80 p-4 backdrop-blur-sm"><div className="max-h-[90vh] w-full max-w-2xl animate-scale-in overflow-auto rounded-xl border bg-card/90 p-5 shadow-glow backdrop-blur-xl"><div className="mb-5 flex items-center justify-between"><h2 className="text-lg font-bold">{title}</h2><button type="button" onClick={onClose} className="premium-button rounded-lg border bg-card/70 p-2"><X className="h-4 w-4" /></button></div>{children}</div></div>; }
function SummaryButton({ label, value, helper, icon, onClick }: { label: string; value: string; helper: string; icon: ReactNode; onClick: () => void }) { return <button onClick={onClick} className="group rounded-lg border bg-card-gradient p-5 text-left shadow-soft transition duration-300 hover:-translate-y-1 hover:shadow-glow"><div className="flex items-start justify-between gap-4"><div><p className="text-sm font-medium text-muted-foreground">{label}</p><p className="mt-2 text-2xl font-bold tracking-tight text-card-foreground">{value}</p></div><div className="rounded-md bg-primary/10 p-3 text-primary transition group-hover:scale-105">{icon}</div></div><p className="mt-5 text-sm text-muted-foreground">{helper}</p></button>; }
function MetricCard({ label, value, helper }: { label: string; value: string; helper?: string }) { return <div className="premium-card p-5"><p className="text-sm font-medium text-muted-foreground">{label}</p><p className="mt-2 text-2xl font-bold text-card-foreground">{value}</p>{helper && <p className="mt-2 text-sm text-muted-foreground">{helper}</p>}</div>; }
function MetricInline({ label, value }: { label: string; value: string }) { return <div><p className="text-xs font-semibold uppercase text-muted-foreground">{label}</p><p className="font-bold">{value}</p></div>; }
function TransactionRow({ transaction, categories }: { transaction: Transaction; categories: FinanceCategory[] }) { return <div className={transaction.category === "Uncategorized" ? "grid gap-3 rounded-md border border-warning/40 bg-warning/10 p-3 sm:grid-cols-[1fr_auto]" : "grid gap-3 rounded-md border bg-background/70 p-3 sm:grid-cols-[1fr_auto]"}><div><p className="font-semibold">{transaction.description}</p><p className="text-sm text-muted-foreground">{transaction.date} • <span style={{ color: categoryColor(categories, transaction.category) }}>{transaction.category}</span> • {transaction.source === "bank" ? "Bank Sync" : "Manual"}</p></div><p className={transaction.type === "income" ? "font-bold text-success" : "font-bold"}>{transaction.type === "income" ? "+" : "-"}{currency(transaction.amount)}</p></div>; }
function EmptyState({ text }: { text: string }) { return <div className="rounded-md border border-dashed bg-muted/30 p-8 text-center text-sm font-medium text-muted-foreground">{text}</div>; }
function InsightList({ title, items }: { title: string; items: string[] }) { return <section className="rounded-xl border bg-card/80 p-5 shadow-soft backdrop-blur-xl"><h2 className="mb-4 text-lg font-bold">{title}</h2><div className="space-y-3">{items.map((item) => <div key={item} className="flex items-center gap-2 rounded-md bg-background/70 p-3 text-sm font-semibold"><ArrowUpRight className="h-4 w-4 text-primary" />{item}</div>)}{items.length === 0 && <EmptyState text="No signal for this period." />}</div></section>; }
function ensurePeriodBudgets(budgets: Budget[], categories: FinanceCategory[], month: number, year: number, transactions: Transaction[]) { return categories.filter((c) => c.name !== "Uncategorized").map((category) => budgets.find((budget) => budget.category === category.name && budget.month === month && budget.year === year) ?? { id: crypto.randomUUID(), category: category.name, month, year, monthlyLimit: Math.max(100, Math.round((spendByCategory(transactions)[category.name] ?? 0) * 1.1)) }); }
function upsertBudget(budgets: Budget[], category: Category, monthlyLimit: number, month: number, year: number) { const exists = budgets.some((budget) => budget.category === category && budget.month === month && budget.year === year); return exists ? budgets.map((budget) => budget.category === category && budget.month === month && budget.year === year ? { ...budget, monthlyLimit } : budget) : [...budgets, { id: crypto.randomUUID(), category, monthlyLimit, month, year }]; }
function groupTransactions(transactions: Transaction[], groupBy: GroupBy) { if (groupBy === "none") return { "All transactions": transactions }; return transactions.reduce<Record<string, Transaction[]>>((acc, transaction) => { const key = groupBy === "date" ? transaction.date : transaction.category; acc[key] = [...(acc[key] ?? []), transaction]; return acc; }, {}); }
function weeklySpending(transactions: Transaction[]) { return [1, 2, 3, 4, 5].map((week) => ({ week: `W${week}`, spent: transactions.filter((t) => t.type === "expense" && Math.ceil(Number(t.date.slice(8, 10)) / 7) === week).reduce((sum, t) => sum + t.amount, 0) })); }
function monthlyTrend(transactions: Transaction[], salary: number) { const keys = Array.from(new Set(transactions.map((t) => t.date.slice(0, 7)))).sort(); return keys.map((key) => { const rows = transactions.filter((t) => t.date.startsWith(key)); const summary = summarize(rows, salary); return { month: key, income: summary.income, expenses: summary.expenses }; }); }

export default SmartFinanceManager;
